import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Input, Button, Card, Separator } from 'decantr/components';
import { link } from 'decantr/router';

code.example:
function AuthForm() {
  const { div, h2, p, span } = tags;
  const [email, setEmail] = createSignal('');
  const [password, setPassword] = createSignal('');

  return div({ class: css('_flex _col _aic _jcc _minhscreen _p6') },
    Card({ class: css('_w[400px] _mw[100%]') },
      Card.Header({},
        h2({ class: css('_heading4 _tc') }, 'Sign In'),
        p({ class: css('_fgmuted _tc _mt1') }, 'Enter your credentials to continue')
      ),
      Card.Body({ class: css('_flex _col _gap3') },
        Input({ label: 'Email', type: 'email', placeholder: 'you@example.com', value: email, onchange: e => setEmail(e.target.value) }),
        Input({ label: 'Password', type: 'password', placeholder: '••••••••', value: password, onchange: e => setPassword(e.target.value) }),
        Button({ variant: 'primary', class: css('_wfull _mt2') }, 'Sign In')
      ),
      Card.Footer({ class: css('_flex _col _gap3 _aic') },
        Separator(),
        span({ class: css('_fgmuted _textsm') }, 'Don\'t have an account? ', link({ href: '/register' }, 'Sign Up'))
      )
    )
  );
}
